const PROCESSING_FEE = 5;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
};

type Item = { type: string };
type QuoteStep = { op: "quote"; items: Item[] };
type Step = QuoteStep;
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
type QuoteResult = { premium: number };
type ScenarioResult = { results: QuoteResult[] };

const basePremiumFor = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;

const quote = (step: QuoteStep): QuoteResult => {
  const itemsTotal = step.items.reduce((sum, item) => sum + basePremiumFor(item), 0);
  return { premium: itemsTotal + PROCESSING_FEE };
};

export const runScenario = (scenario: Scenario): ScenarioResult => ({
  results: scenario.steps.map(quote),
});
